const LOOKUP = new Map<string, number>()
for (const [s, r, ms] of RAW) {
  LOOKUP.set(s + "|" + r, ms)
}

export function getLatency(from: string, to: string): number | undefined {
  return LOOKUP.get(from + "|" + to) ?? LOOKUP.get(to + "|" + from)
}

export function getLatencyNormalized(from: string, to: string): number | undefined {
  const ms = getLatency(from, to)
  return ms != null ? (ms - 0.3) / (345.8 - 0.3) : undefined
}

export { RAW as LATENCY_PAIRS }
